3	const BASE = 'http://localhost:80/api'
4	
5	export async function apiToken(request: APIRequestContext, identifier: string, password: string): Promise<string> {
6	  const res = await request.post(`${BASE}/auth/login`, {
7	    headers: { 'X-Client-Type': 'api' },
8	    data: { identifier, password }
9	  })
10	  const body = await res.json()
11	  return body?.data?.access_token || body?.data?.token || body?.token || ''
12	}
