14	export async function apiGet(request: APIRequestContext, token: string, path: string, params = {}) {
15	  const url = new URL(`${BASE}${path}`)
16	  Object.entries(params).forEach(([k, v]) => url.searchParams.set(k, String(v)))
17	  const res = await request.get(url.toString(), {
18	    headers: { Authorization: `Bearer ${token}` }
19	  })
20	  return res.json()
21	}
