23	export async function apiPost(request: APIRequestContext, token: string, path: string, data: object) {
24	  const res = await request.post(`${BASE}${path}`, {
25	    headers: { Authorization: `Bearer ${token}` },
26	    data
27	  })
28	  return res.json()
29	}
