1	export const extractError = (error, fallback = 'Request failed.') => {
2	  const body = error?.response?.data
3	
4	  // Laravel standard 422: { message, errors: { field: ["msg"] } }
5	  if (body?.errors && typeof body.errors === 'object') {
6	    const msgs = Object.values(body.errors).flat()
7	    if (msgs.length) return msgs.join(' ')
8	  }
9	
10	  // Custom API format: { success: false, error: "VALIDATION_ERROR", data: { field: ["msg"] } }
11	  if (body?.error === 'VALIDATION_ERROR' && body?.data && typeof body.data === 'object') {
12	    const msgs = Object.values(body.data).flat()
13	    if (msgs.length) return msgs.join(' ')
14	  }
15	
16	  return body?.error || body?.message || fallback
17	}
