  await deleteBtn.click()
  const confirmBtn = page.getByRole('button', { name: /^delete$/i }).last()
  if (await confirmBtn.isVisible()) {
    await confirmBtn.click()
  }
  await expect(page.locator('.el-message')).toBeVisible({ timeout: 8000 })
})
"}

