  }

  const submitBtn = page.getByRole('button', { name: /post payment|submit|confirm/i }).first()
  await submitBtn.click()

  // Assert the button enters a disabled or loading state after click (submit guard)
  const isDisabled = await submitBtn.isDisabled()
  const isLoading = (await page.locator('.is-loading').count()) > 0
  // If the form submitted instantly, the success/error response is also acceptable
  const hasSuccessResponse = (await page.locator('.el-message--success').count()) > 0
  const hasErrorResponse = (await page.locator('.el-message--error, .el-message--warning').count()) > 0

  // The button must either be in a guarded state OR have already resolved with a response
