  const count = await rows.count()

  if (count > 0) {
    // Confirmed rows show Check In button — no Confirm (requested) or Complete (checked_in) buttons
    await expect(rows.first().getByRole('button', { name: 'Check In' })).toBeVisible({ timeout: 5000 })
