    // Verify the binding exists in the rendered HTML
    expect(wrapper.html()).toContain('disabled')

    resolveCreate({ success: true })
    await p
    await flush()

    // After resolve — submitting resets
    expect(wrapper.vm.submitting).toBe(false)
  })"}

